mapper.select:
/* selectAdmin1001List */ SELECT d.dept_oid, d.dept_nm, d.up_dept_oid, p.dept_nm as parent_name, d.sort_seq, d.use_yn, d.reg_id, d.reg_dt, d.mdfcn_id, d.mdfcn_dt, (SELECT COUNT(*) FROM ${schema}.dept_mmbr dm WHERE dm.dept_oid = d.dept_oid) as member_count, (SELECT COUNT(*) FROM ${schema}.dept c WHERE c.up_dept_oid = d.dept_oid AND c.use_yn = 'Y') as child_count FROM ${schema}.dept d LEFT JOIN ${schema}.dept p ON d.up_dept_oid = p.dept_oid
AND d.dept_nm LIKE CONCAT('%', #{deptNm}, '%')
AND d.up_dept_oid = #{upDeptOid}
AND d.use_yn = #{useYn}
ORDER BY CASE WHEN d.up_dept_oid IS NULL THEN 0 ELSE 1 END, d.up_dept_oid, d.sort_seq, d.dept_oid

/* checkChildDept */
SELECT COUNT(*)
FROM ${schema}.dept
WHERE up_dept_oid = #{deptOid}
  AND use_yn = 'Y'

/* checkDeptMembers */
SELECT COUNT(*)
FROM ${schema}.dept_mmbr
WHERE dept_oid = #{deptOid}

mapper.update:
/* updateSortSeq */
UPDATE ${schema}.dept
SET sort_seq  = #{sortSeq},
    mdfcn_id = #{mdfcnId},
    mdfcn_dt      = NOW()
WHERE dept_oid = #{deptOid}
